#!/usr/bin/env bash
# general-playbook.sh — 通用 Playbook 决策助手 for UBNT/UniFi 企业 Wi-Fi 工程.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="UBNT/UniFi 企业 Wi-Fi 工程"
TOPIC="通用 Playbook"

usage() {
  cat <<EOF
general-playbook.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 6 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./general-playbook.sh             # interactive
  ./general-playbook.sh --dry-run   # walk through but no file
  ./general-playbook.sh --json      # JSON to stdout
  ./general-playbook.sh --explain   # show backing playbook rules + mental models
  ./general-playbook.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 通用 Playbook 主题下的 playbook 规则组合成交互树。

基于 6 条规则:
  • 如果 80-150 人密集办公, 现有 Wi-Fi 慢/不稳 → 则 先做 retry-rate + channel-utilization 诊断, NOT 加 AP
  • 如果 voice / video 漫游粘连 → 则 同时启用 11k+11v+11r 三件套, 并按 client inventory staged rollout
  • 如果 升级 UniFi controller / Network App → 则 先看 CVE diff 再看 feature notes; CVE-critical 即升, feature-only 
  • 如果 即将 production change → 则 (新 SSID / VLAN / firewall / AP firmware), 则 snapshot backup 
  • 如果 启用 WPA3 / PMF → 则 用 hostapd-mana + nmap 真测 fallback + VLAN 隔离, 不许 "GUI 写了 WPA3
  • 如果 想做 AIOps-style 监控 → 则 day 1 装 unpoller + Grafana + Prometheus, 不要 phase 2 再补; LLM 

相关心智模型:
  • 容量优先, 覆盖次之 (Capacity-first, coverage second): 80 人密集办公的 Wi-Fi 瓶颈不是覆盖, 是同信道干扰 (CCI) — 加 AP 反而让网络更慢; 工程师先算 airtime budget, 后摆 AP.
  • Retry rate > RSSI (重试率比信号强度更能定位问题): 客户跟你说 "信号差", 你先要 retry % 和 channel utilization, 不要 RSSI — RSSI 满格但 retry 30% (业内估计 — CCI 阈值) 是 CCI /

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "80-150 人密集办公, 现有 Wi-Fi 慢/不稳"
  "voice / video 漫游粘连"
  "升级 UniFi controller / Network App"
  "即将 production change"
  "启用 WPA3 / PMF"
  "想做 AIOps-style 监控"
)
declare -a RULE_ACTIONS=(
  "先做 retry-rate + channel-utilization 诊断, NOT 加 AP"
  "同时启用 11k+11v+11r 三件套, 并按 client inventory staged rollout"
  "先看 CVE diff 再看 feature notes; CVE-critical 即升, feature-only 排到 maintenance Saturday"
  "(新 SSID / VLAN / firewall / AP firmware), 则 snapshot backup 或 config-as-code 先做, 不许 \"我快速改一下\""
  "用 hostapd-mana + nmap 真测 fallback + VLAN 隔离, 不许 \"GUI 写了 WPA3 就算\""
  "day 1 装 unpoller + Grafana + Prometheus, 不要 phase 2 再补; LLM agent (unifi-mcp / Claude) 一律 read-only + propose-then-approve gate, 不许直接写 firewall"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "general-playbook-decision"
fi
